        self.parent = parent
        self.n = len(parent)
        self.children = [[] for _ in range(self.n)]
        for i, p in enumerate(parent):
            if p != -1:
                self.children[p].append(i)
        self.locked_by = [-1] * self.n

    def lock(self, num, user):
        if self.locked_by[num] != -1:
            return False
        self.locked_by[num] = user
        return True

    def unlock(self, num, user):
        if self.locked_by[num] != user:
            return False
        self.locked_by[num] = -1
        return True

    def _has_locked_ancestor(self, num):
        p = self.parent[num]
        while p != -1:
            if self.locked_by[p] != -1:
                return True
            p = self.parent[p]
        return False

    def _locked_descendants(self, num):
        found = []
        stack = list(self.children[num])
        while stack:
            node = stack.pop()
            if self.locked_by[node] != -1:
                found.append(node)
            stack.extend(self.children[node])
        return found

    def upgrade(self, num, user):
        if self.locked_by[num] != -1:
            return False
        if self._has_locked_ancestor(num):
            return False
        descendants = self._locked_descendants(num)
        if not descendants:
            return False
        for d in descendants:
            self.locked_by[d] = -1
        self.locked_by[num] = user
        return True

