class LockingTree {
    constructor(parent) {
        this.parent = parent;
        this.n = parent.length;
        this.children = Array.from({ length: this.n }, () => []);
        for (let i = 0; i < this.n; i++) {
            if (parent[i] !== -1) this.children[parent[i]].push(i);
        }
        this.lockedBy = new Array(this.n).fill(-1);
    }

    lock(num, user) {
        if (this.lockedBy[num] !== -1) return false;
        this.lockedBy[num] = user;
        return true;
    }

    unlock(num, user) {
        if (this.lockedBy[num] !== user) return false;
        this.lockedBy[num] = -1;
        return true;
    }

    _hasLockedAncestor(num) {
        let p = this.parent[num];
        while (p !== -1) {
            if (this.lockedBy[p] !== -1) return true;
            p = this.parent[p];
        }
        return false;
    }

    _lockedDescendants(num) {
        const found = [];
        const stack = [...this.children[num]];
        while (stack.length) {
            const node = stack.pop();
            if (this.lockedBy[node] !== -1) found.push(node);
            for (const c of this.children[node]) stack.push(c);
        }
        return found;
    }

    upgrade(num, user) {
        if (this.lockedBy[num] !== -1) return false;
        if (this._hasLockedAncestor(num)) return false;
        const descendants = this._lockedDescendants(num);
        if (descendants.length === 0) return false;
        for (const d of descendants) this.lockedBy[d] = -1;
        this.lockedBy[num] = user;
        return true;
    }
}
